.load extensions/exif/target/wasm32-wasip2/release/exif_extension.component.wasm

/* EXIF metadata extraction.
 *
 * Per PLAN-more-extensions-3.md  4 acceptance:
 *   - JPEG fixture with known EXIF: camera + datetime + GPS match
 *   - PNG blob (no EXIF segment): every fn returns NULL
 *   - Random bytes: every fn returns NULL (no error)
 *   - exif_orientation in 1..=8
 *   - GPS values are signed decimal degrees (S/W negative)
 *
 * Fixtures (all hex literals):
 *
 *   jpeg_full:   a synthesized 314-byte JPEG envelope (SOI + APP1 +
 *                EXIF TIFF + EOI). Built via kamadak-exif's
 *                experimental Writer; carries Make=TestCam,
 *                Model=X100, DateTimeOriginal=2024-01-15 10:30:45,
 *                Orientation=1, PhotographicSensitivity=400,
 *                FNumber=2.8, ExposureTime=1/250, FocalLength=50,
 *                GPSLatitude=37 deg 46' 29.64", N
 *                GPSLongitude=122 deg 25' 15.84", W.
 *
 *   png_min:     8-byte PNG signature + IHDR  no EXIF chunk. kamadak's
 *                PNG path returns Err(NoExif), which we collapse to
 *                SQL NULL.
 *
 *   random:      12 bytes of 0xAA  matches no container signature;
 *                read_from_container returns InvalidFormat -> NULL.
 */

------------------------------------------------------------------
-- Acceptance 1: full JPEG -> camera/make/model/datetime/orientation
------------------------------------------------------------------
SELECT exif_make(x'');
SELECT exif_model(x'');
SELECT exif_camera(x'');
SELECT exif_datetime(x'');
SELECT exif_orientation(x'');

------------------------------------------------------------------
-- Acceptance 2: camera capture settings
------------------------------------------------------------------
SELECT exif_iso(x'');
SELECT exif_aperture(x'');
SELECT exif_shutter_speed(x'');
SELECT exif_focal_length(x'');

------------------------------------------------------------------
-- Acceptance 3: GPS  signed decimal degrees, rounded for stable diff
-- Lat = 37 + 46/60 + 29.64/3600 = 37.7749 (N positive)
-- Lng = -(122 + 25/60 + 15.84/3600) ~ -122.4211 (W negative)
------------------------------------------------------------------
SELECT round(exif_gps_lat(x''), 4);
SELECT round(exif_gps_lng(x''), 4);
-- exif_gps_lng MUST be negative for W (W is below the prime meridian).
SELECT exif_gps_lng(x'') < 0;

------------------------------------------------------------------
-- Acceptance 4: orientation in 1..=8
------------------------------------------------------------------
SELECT exif_orientation(x'') BETWEEN 1 AND 8;

------------------------------------------------------------------
-- Acceptance 5: exif_field arbitrary-tag accessor
------------------------------------------------------------------
SELECT exif_field(x'', 'Make');
SELECT exif_field(x'', 'NotARealTag');

------------------------------------------------------------------
-- Acceptance 6: exif_all returns parseable JSON; spot-check via json_extract
------------------------------------------------------------------
SELECT json_extract(exif_all(x''), '$.Make');

------------------------------------------------------------------
-- Acceptance 7: PNG with no EXIF chunk -> NULL on every fn
-- 8-byte PNG signature + IHDR for a 1x1 image, no eXIf chunk.
------------------------------------------------------------------
SELECT exif_make(x'89504E470D0A1A0A0000000D49484452000000010000000108020000009077533D');
SELECT exif_model(x'89504E470D0A1A0A0000000D49484452000000010000000108020000009077533D');
SELECT exif_datetime(x'89504E470D0A1A0A0000000D49484452000000010000000108020000009077533D');
SELECT exif_gps_lat(x'89504E470D0A1A0A0000000D49484452000000010000000108020000009077533D');
SELECT exif_orientation(x'89504E470D0A1A0A0000000D49484452000000010000000108020000009077533D');
SELECT exif_iso(x'89504E470D0A1A0A0000000D49484452000000010000000108020000009077533D');

------------------------------------------------------------------
-- Acceptance 8: random bytes -> NULL on every fn (no error)
------------------------------------------------------------------
SELECT exif_make(x'AAAAAAAAAAAAAAAAAAAAAAAA');
SELECT exif_model(x'AAAAAAAAAAAAAAAAAAAAAAAA');
SELECT exif_datetime(x'AAAAAAAAAAAAAAAAAAAAAAAA');
SELECT exif_gps_lat(x'AAAAAAAAAAAAAAAAAAAAAAAA');
SELECT exif_gps_lng(x'AAAAAAAAAAAAAAAAAAAAAAAA');
SELECT exif_orientation(x'AAAAAAAAAAAAAAAAAAAAAAAA');
SELECT exif_iso(x'AAAAAAAAAAAAAAAAAAAAAAAA');
SELECT exif_aperture(x'AAAAAAAAAAAAAAAAAAAAAAAA');
SELECT exif_shutter_speed(x'AAAAAAAAAAAAAAAAAAAAAAAA');
SELECT exif_focal_length(x'AAAAAAAAAAAAAAAAAAAAAAAA');
SELECT exif_all(x'AAAAAAAAAAAAAAAAAAAAAAAA');
SELECT exif_field(x'AAAAAAAAAAAAAAAAAAAAAAAA', 'Make');

------------------------------------------------------------------
-- Acceptance 9: NULL input -> NULL on every fn
------------------------------------------------------------------
SELECT exif_make(NULL);
SELECT exif_gps_lat(NULL);
SELECT exif_all(NULL);

------------------------------------------------------------------
-- Acceptance 10: version is a non-empty TEXT
------------------------------------------------------------------
SELECT length(exif_version()) > 0;
